+fn is_probably_binary(data: &[u8]) -> bool {
+    if data.is_empty() {
+        return false;
+    }
+    if data.contains(&0) {
+        return true;
+    }
+
+    let control_count = data
+        .iter()
+        .filter(|byte| {
+            matches!(
+                **byte,
+                0x01..=0x08 | 0x0B | 0x0C | 0x0E..=0x1F | 0x7F
+            )
+        })
+        .count();
+    control_count.saturating_mul(5) > data.len()
+}
